1	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Damage = { itemType: string; amount: number };
4	type Incident = { cause: string; damages: Damage[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Customer = { yearsWithMHPCO: number };
8	type Scenario = {
9	  customer: Customer;
10	  steps: Step[];
11	};
12	type QuoteResult = { premium: number };
13	type ClaimResult = { payout: number; remainingCap: number };
14	type StepResult = QuoteResult | ClaimResult;
15	
16	const PROCESSING_FEE = 5;
17	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
18	const CURSE_SURCHARGE_RATE = 0.5;
19	const HIGH_ENCHANT_SURCHARGE_RATE = 0.3;
20	const HIGH_ENCHANT_THRESHOLD = 5;
21	const LOYALTY_DISCOUNT_RATE = 0.2;
22	const LOYALTY_YEARS = 2;
23	const BLOCK_SIZE = 3;
24	const BLOCK_BASE_PREMIUM = 60;
25	
26	const BASE_PREMIUMS: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	  potion: 40,
31	  rune: 25,
32	  moonstone: 25,
33	};
34	
35	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
36	
37	const countByType = (items: Item[]): Map<string, number> => {
38	  const counts = new Map<string, number>();
39	  for (const item of items) {
40	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
41	  }
42	  return counts;
43	};
44	
45	const componentsBase = (components: Item[]): number => {
46	  let total = 0;
47	  for (const [type, count] of countByType(components)) {
48	    total += count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUMS[type];
49	  }
50	  return total;
51	};
52	
53	const mainItemsBase = (items: Item[]): number =>
54	  items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
55	
56	const itemSurcharges = (item: Item): number => {
57	  const base = BASE_PREMIUMS[item.type];
58	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
59	  const highEnchant = (item.enchantment ?? 0) >= HIGH_ENCHANT_THRESHOLD ? base * HIGH_ENCHANT_SURCHARGE_RATE : 0;
60	  return curse + highEnchant;
61	};
62	
63	const quotePremium = (step: QuoteStep, customer: Customer): QuoteResult => {
64	  const mainItems = step.items.filter((i) => !COMPONENT_TYPES.has(i.type));
65	  const components = step.items.filter((i) => COMPONENT_TYPES.has(i.type));
66	
67	  const policyBase = mainItemsBase(mainItems) + componentsBase(components);
68	  const firstInsurance = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
69	  const surcharges = mainItems.reduce((sum, item) => sum + itemSurcharges(item), 0);
70	  const loyalty = customer.yearsWithMHPCO >= LOYALTY_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
71	
72	  return { premium: Math.ceil(policyBase + firstInsurance + surcharges - loyalty + PROCESSING_FEE) };
73	};
74	
75	const DEDUCTIBLE = 100;
76	const CAP_MULTIPLIER = 2;
77	
78	const INSURANCE_VALUES: Record<string, number> = {
79	  sword: 1000,
80	  amulet: 600,
81	  staff: 800,
82	  potion: 400,
83	  rune: 250,
84	  moonstone: 250,
85	};
86	
87	const insuranceSum = (items: Item[]): number =>
88	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
89	
90	const HIGH_ENCHANT_PAYOUT_THRESHOLD = 8;
91	const HIGH_ENCHANT_PAYOUT_RATE = 0.5;
92	
93	const reimbursementRate = (item: Item | undefined): number =>
94	  (item?.enchantment ?? 0) >= HIGH_ENCHANT_PAYOUT_THRESHOLD ? HIGH_ENCHANT_PAYOUT_RATE : 1;
95	
96	const damagePayout = (damage: Damage, policyItems: Item[]): number => {
97	  const item = policyItems.find((i) => i.type === damage.itemType);
98	  return Math.max(0, damage.amount * reimbursementRate(item) - DEDUCTIBLE);
99	};
100	
101	const claimResult = (step: ClaimStep, policyItems: Item[], availableCap: number): ClaimResult => {
102	  const rawPayout = step.incident.damages.reduce(
103	    (sum, d) => sum + damagePayout(d, policyItems),
104	    0,
105	  );
106	  const payout = Math.min(rawPayout, availableCap);
107	  return { payout, remainingCap: availableCap - payout };
108	};
109	
110	const policyItemsFor = (step: ClaimStep, steps: Step[]): Item[] => {
111	  const policyStep = steps[step.policy];
112	  if (policyStep.op !== "quote") {
113	    throw new Error(`step ${step.policy} is not a quote`);
114	  }
115	  return policyStep.items;
116	};
117	
118	export const run = (scenario: Scenario): { results: StepResult[] } => {
119	  const results: StepResult[] = [];
120	  const remainingCapByPolicy = new Map<number, number>();
121	  for (const step of scenario.steps) {
122	    if (step.op === "quote") {
123	      results.push(quotePremium(step, scenario.customer));
124	    } else {
125	      const policyItems = policyItemsFor(step, scenario.steps);
126	      const available =
127	        remainingCapByPolicy.get(step.policy) ?? insuranceSum(policyItems) * CAP_MULTIPLIER;
128	      const result = claimResult(step, policyItems, available);
129	      remainingCapByPolicy.set(step.policy, result.remainingCap);
130	      results.push(result);
131	    }
132	  }
133	  return { results };
134	};
